function imgExst = fDutchShtLstV01(espcDir,nmbSht,camNmb) %% returns a list of image exist logic for dutch magnet% % imgExst = fDutchShtLstV01(espcDir,nmbSht,camNmb)%% espcDir: directory to check image% nmbSht: number of shots from trex logfile% camNmb: camera number%% imgExst: logic of image exist%% Kei Nakamura% Created on Tuesday, November 16th 2010.% Modified on%%% main bodyname = ['/*_Dutch',num2str(camNmb),'*.png'];    % general name for imageimgLst = dir([espcDir,name]);         % image list[nmbImg,dlt] = size(imgLst);   % number of imagesimgExst = zeros(nmbSht,1);        % array for shot existfor jj=1:nmbImg    name = imgLst(jj).name;    prt = fGetPartStrV03(name,'_','g');    prt = fGetPartStrV03(prt,'_','.'); % since there are two _    imgExst(str2num(prt)) = 1;      % make logic 1end
